import {Component, signal, computed} from '@angular/core';
import {bootstrapApplication} from '@angular/platform-browser';

@Component({
  selector: 'app-root',
  template: `
    <h2>Cookie recipe</h2>

    <label>
      # of cookies:
      <input type="range" min="10" max="100" step="10" [value]="count()" (input)="update($event)" />
      {{ count() }}
    </label>

    <p>Butter: {{ butter() }} cup(s)</p>
    <p>Sugar: {{ sugar() }} cup(s)</p>
    <p>Flour: {{ flour() }} cup(s)</p>
  `,
})
export class CookieRecipe {
  readonly count = signal(10);

  readonly butter = computed(() => this.count() * 0.1);
  readonly sugar = computed(() => this.count() * 0.05);
  readonly flour = computed(() => this.count() * 0.2);

  update(event: Event) {
    const input = event.target as HTMLInputElement;
    this.count.set(parseInt(input.value));
  }
}

bootstrapApplication(CookieRecipe);

import { isString } from '../is';

export const isValidWaveColor = (
  color: CSSStyleDeclaration[keyof CSSStyleDeclaration],
): color is string => {
  if (!color) {
    return false;
  }
  return (
    isString(color) &&
    color !== '#fff' &&
    color !== '#ffffff' &&
    color !== 'rgb(255, 255, 255)' &&
    color !== 'rgba(255, 255, 255, 1)' &&
    !/rgba\((?:\d*, ){3}0\)/i.test(color) && // any transparent rgba color
    !/^#(?:[0-9a-f]{3}0|[0-9a-f]{6}00)$/i.test(color) && // any transparent hex color
    color !== 'transparent' &&
    color !== 'canvastext'
  );
};

export function getTargetWaveColor(
  node: HTMLElement,
  colorSource: keyof CSSStyleDeclaration | null = null,
): string | null {
  const style = getComputedStyle(node);
  const { borderTopColor, borderColor, backgroundColor } = style;

  if (colorSource && isValidWaveColor(style[colorSource])) {
    return style[colorSource];
  }

  return [borderTopColor, borderColor, backgroundColor].find(isValidWaveColor) ?? null;
}

