export function getExtension(path: string): string | undefined {
  const filename = path.split("/").pop();
  if (!filename) {
    return;
  }
  const separatorIndex = filename.lastIndexOf(".");
  if (separatorIndex !== -1) {
    return filename.slice(separatorIndex);
  }
}

export function getType(ext: string | undefined): string | undefined {
  return ext ? COMMON_MIME_TYPES[ext] : undefined;
}

import "#nitro/virtual/polyfills";
import { useNitroApp, getRouteRules } from "nitro/app";

import type { ServerRequest } from "srvx";
import { isrRouteRewrite } from "./isr.ts";

const nitroApp = useNitroApp();

export default {
  fetch(req: ServerRequest, context: { waitUntil: (promise: Promise<any>) => void }) {
    // ISR route rewrite
    const isrURL = isrRouteRewrite(req.url, req.headers.get("x-now-route-matches"));
    if (isrURL) {
      const { routeRules } = getRouteRules("", isrURL[0]);
      if (routeRules?.isr) {
        req = new Request(
          new URL(isrURL[0] + (isrURL[1] ? `?${isrURL[1]}` : ""), req.url).href,
          req
        );
      }
    }

    req.runtime ??= { name: "vercel" };
    req.runtime.vercel = { context };

    let ip: string | undefined;
    Object.defineProperty(req, "ip", {
      get() {
        const h = req.headers.get("x-forwarded-for");
        return (ip ??= h?.split(",").shift()?.trim());
      },
    });

    req.waitUntil = context?.waitUntil;

    return nitroApp.fetch(req);
  },
};

